+{
+  "suite": "core_cluster",
+  "cases": [
+    {
+      "name": "cluster_info",
+      "now_ms": 0,
+      "argv": ["CLUSTER", "INFO"],
+      "expect": {
+        "kind": "bulk",
+        "value": "cluster_enabled:0\r\ncluster_state:ok\r\ncluster_slots_assigned:0\r\ncluster_slots_ok:0\r\ncluster_slots_pfail:0\r\ncluster_slots_fail:0\r\ncluster_known_nodes:0\r\ncluster_size:0\r\ncluster_current_epoch:0\r\ncluster_my_epoch:0\r\ncluster_stats_messages_sent:0\r\ncluster_stats_messages_received:0\r\ntotal_cluster_links_buffer_limit_exceeded:0\r\n"
+      }
+    },
+    {
+      "name": "cluster_myid",
+      "now_ms": 0,
+      "argv": ["CLUSTER", "MYID"],
+      "expect": {
+        "kind": "bulk",
+        "value": "0000000000000000000000000000000000000000"
+      }
+    },
+    {
+      "name": "cluster_slots_empty",
+      "now_ms": 0,
+      "argv": ["CLUSTER", "SLOTS"],
+      "expect": {
+        "kind": "array",
+        "value": []
+      }
+    },
+    {
+      "name": "cluster_shards_empty",
+      "now_ms": 0,
+      "argv": ["CLUSTER", "SHARDS"],
+      "expect": {
+        "kind": "array",
+        "value": []
+      }
+    },
+    {
+      "name": "cluster_nodes_empty",
+      "now_ms": 0,
+      "argv": ["CLUSTER", "NODES"],
+      "expect": {
+        "kind": "bulk",
+        "value": ""
+      }
+    },
+    {
+      "name": "cluster_reset",
+      "now_ms": 0,
+      "argv": ["CLUSTER", "RESET"],
+      "expect": { "kind": "simple", "value": "OK" }
+    },
+    {
+      "name": "cluster_keyslot_foo",
+      "now_ms": 0,
+      "argv": ["CLUSTER", "KEYSLOT", "foo"],
+      "expect": { "kind": "integer", "value": 12182 }
+    },
+    {
+      "name": "cluster_keyslot_bar",
+      "now_ms": 0,
+      "argv": ["CLUSTER", "KEYSLOT", "bar"],
+      "expect": { "kind": "integer", "value": 5061 }
+    },
+    {
+      "name": "cluster_keyslot_hello",
+      "now_ms": 0,
+      "argv": ["CLUSTER", "KEYSLOT", "hello"],
+      "expect": { "kind": "integer", "value": 866 }
+    },
+    {
+      "name": "cluster_keyslot_hash_tag",
+      "now_ms": 0,
+      "argv": ["CLUSTER", "KEYSLOT", "{user}.following"],
+      "expect": { "kind": "integer", "value": 5474 }
+    },
+    {
+      "name": "cluster_keyslot_hash_tag_same_as_inner",
+      "now_ms": 0,
+      "argv": ["CLUSTER", "KEYSLOT", "user"],
+      "expect": { "kind": "integer", "value": 5474 }
+    },
+    {
+      "name": "cluster_keyslot_empty_hash_tag_uses_full_key",
+      "now_ms": 0,
+      "argv": ["CLUSTER", "KEYSLOT", "{}.foo"],
+      "expect": { "kind": "integer", "value": 64 }
+    },
+    {
+      "name": "setup_cluster_keys",
+      "now_ms": 0,
+      "argv": ["SET", "foo", "val1"],
+      "expect": { "kind": "simple", "value": "OK" }
+    },
+    {
+      "name": "setup_cluster_keys_2",
+      "now_ms": 0,
+      "argv": ["SET", "bar", "val2"],
+      "expect": { "kind": "simple", "value": "OK" }
+    },
+    {
+      "name": "cluster_countkeysinslot_with_key",
+      "now_ms": 0,
+      "argv": ["CLUSTER", "COUNTKEYSINSLOT", "12182"],
+      "expect": { "kind": "integer", "value": 1 }
+    },
+    {
+      "name": "cluster_countkeysinslot_empty",
+      "now_ms": 0,
+      "argv": ["CLUSTER", "COUNTKEYSINSLOT", "0"],
+      "expect": { "kind": "integer", "value": 0 }
+    },
+    {
+      "name": "cluster_getkeysinslot_with_key",
+      "now_ms": 0,
+      "argv": ["CLUSTER", "GETKEYSINSLOT", "12182", "10"],
+      "expect": {
+        "kind": "array",
+        "value": [
+          { "kind": "bulk", "value": "foo" }
+        ]
+      }
+    },
+    {
+      "name": "cluster_getkeysinslot_empty",
+      "now_ms": 0,
+      "argv": ["CLUSTER", "GETKEYSINSLOT", "0", "10"],
+      "expect": {
+        "kind": "array",
+        "value": []
+      }
+    },
+    {
+      "name": "cluster_getkeysinslot_count_zero",
+      "now_ms": 0,
+      "argv": ["CLUSTER", "GETKEYSINSLOT", "12182", "0"],
+      "expect": {
+        "kind": "array",
+        "value": []
+      }
+    },
+    {
+      "name": "cluster_help",
+      "now_ms": 0,
+      "argv": ["CLUSTER", "HELP"],
+      "expect": {
+        "kind": "array",
+        "value": [
+          { "kind": "bulk", "value": "CLUSTER HELP" },
+          { "kind": "bulk", "value": "CLUSTER subcommand dispatch scaffold (FR-P2C-007 D1)." },
+          { "kind": "bulk", "value": "Supported subcommands in this stage: HELP, INFO, MYID, SLOTS, SHARDS, NODES, KEYSLOT, GETKEYSINSLOT, COUNTKEYSINSLOT, RESET." }
+        ]
+      }
+    },
+    {
+      "name": "cluster_wrong_arity",
+      "now_ms": 0,
+      "argv": ["CLUSTER"],
+      "expect": { "kind": "error", "value": "ERR wrong number of arguments for 'CLUSTER' command" }
+    },
+    {
+      "name": "cluster_unknown_subcommand",
+      "now_ms": 0,
+      "argv": ["CLUSTER", "NOSUCH"],
+      "expect": { "kind": "error", "value": "ERR Unknown subcommand or wrong number of arguments for 'CLUSTER'. Try CLUSTER HELP." }
+    },
+    {
+      "name": "cluster_keyslot_wrong_arity",
+      "now_ms": 0,
+      "argv": ["CLUSTER", "KEYSLOT"],
+      "expect": { "kind": "error", "value": "ERR wrong number of arguments for 'CLUSTER' command" }
+    },
+    {
+      "name": "cluster_countkeysinslot_wrong_arity",
+      "now_ms": 0,
+      "argv": ["CLUSTER", "COUNTKEYSINSLOT"],
+      "expect": { "kind": "error", "value": "ERR wrong number of arguments for 'CLUSTER' command" }
+    },
+    {
+      "name": "cluster_getkeysinslot_wrong_arity",
+      "now_ms": 0,
+      "argv": ["CLUSTER", "GETKEYSINSLOT", "0"],
+      "expect": { "kind": "error", "value": "ERR wrong number of arguments for 'CLUSTER' command" }
+    },
+    {
+      "name": "cluster_case_insensitive",
+      "now_ms": 0,
+      "argv": ["CLUSTER", "info"],
+      "expect": {
+        "kind": "bulk",
+        "value": "cluster_enabled:0\r\ncluster_state:ok\r\ncluster_slots_assigned:0\r\ncluster_slots_ok:0\r\ncluster_slots_pfail:0\r\ncluster_slots_fail:0\r\ncluster_known_nodes:0\r\ncluster_size:0\r\ncluster_current_epoch:0\r\ncluster_my_epoch:0\r\ncluster_stats_messages_sent:0\r\ncluster_stats_messages_received:0\r\ntotal_cluster_links_buffer_limit_exceeded:0\r\n"
+      }
+    }
+  ]
+}

